from flask import Flask, request, session
from xml.etree import ElementTree as ET
import base64, zlib

app = Flask(__name__)
app.secret_key = 'YOUR_SECRET_KEY'

def decode_SAML_assertion(saml_response):
    #Decoding the SAML Response 
    decoded_data = base64.b64decode(saml_response)
    #Inflate the decoded SAML Response
    saml_data = zlib.decompress(decoded_data, -15).decode()
    return saml_data

def validate_SAML_assertion(saml_data):
    # Parse XML using ElementTree
    root = ET.fromstring(saml_data)
    # get Assertion block
    assertion = root.find('{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    return bool(assertion)

@app.route('/acs', methods = ['POST'])
def acs():
    saml_response = request.form.get('SAMLResponse')
    saml_data = decode_SAML_assertion(saml_response)

    if not validate_SAML_assertion(saml_data):
        return "Invalid SAML Assertion received."

    root = ET.fromstring(saml_data)
    session['user_attributes'] = {}

    for attributeStatement in root.iter('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement'):
        for attribute in attributeStatement.iter('{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attribute.attrib['Name']
            attr_value = attribute[0].text
            session['user_attributes'][attr_name] = attr_value

    return "SAML Assertion processed."

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)